#include <iostream>
using namespace std;
class Solution {
public:
    int solve(vector<int>& nums) {
        long long sum_squares = 0;
        for (int i : nums)
            sum_squares += i * i;
        return sum_squares;
    }
};
int main() {
    Solution solution;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++)
        cin >> nums[i];
    cout << solution.solve(nums) << endl;
    return 0;
}
